import React, { useEffect, useState } from 'react'
import { useNavigate, useLocation } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { Home, Map, Bell, MessageSquare, User, Plus, LayoutDashboard, BarChart3 } from 'lucide-react'
import { useAuth } from '@/contexts/AuthContext'
import { supabase } from '@/integrations/supabase/client'

/* ─── Manus AI x AgriLink Design System (Light Mode) ─────────────────────── */
const B = {
  // AgriLink Core
  brand:      '#1B8A3D', // Verde principal
  brandLight: '#72B344', // Verde alface
  
  // Manus AI Neutrals (Light)
  ink:        '#0A0C0B', // Quase preto profundo
  slate:      '#4A4F4C', // Cinza ardósia
  silver:     '#E2E4E2', // Prata para bordas
  white:      '#FFFFFF',
  snow:       '#F9FAFA', // Branco neve para fundos
  
  // Transparencies
  glass:      'rgba(255, 255, 255, 0.9)', // Vidro branco
  shadow:     'rgba(10, 12, 11, 0.08)',
}

const BottomNavigation = () => {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const location = useLocation()
  const { isAdmin, user } = useAuth()
  const [unreadNotifications, setUnreadNotifications] = useState(0)
  const [unreadMessages, setUnreadMessages] = useState(0)

  useEffect(() => {
    if (!user?.id) return
    const fetchCounts = async () => {
      const { count: notifCount } = await supabase
        .from('notifications').select('*', { count:'exact', head:true })
        .eq('user_id', user.id).eq('read', false)
      setUnreadNotifications(notifCount || 0)

      const { count: msgCount } = await supabase
        .from('messages').select('*', { count:'exact', head:true })
        .eq('receiver_id', user.id).eq('read', false)
      setUnreadMessages(msgCount || 0)
    }
    fetchCounts()

    const notifChannel = supabase.channel('notifications-count')
      .on('postgres_changes', { event:'*', schema:'public', table:'notifications', filter:`user_id=eq.${user.id}` }, fetchCounts)
      .subscribe()
    const msgChannel = supabase.channel('messages-count')
      .on('postgres_changes', { event:'*', schema:'public', table:'messages', filter:`receiver_id=eq.${user.id}` }, fetchCounts)
      .subscribe()

    return () => { supabase.removeChannel(notifChannel); supabase.removeChannel(msgChannel) }
  }, [user?.id])

  // Item de publicação (Ação principal)
  const publishItem = { 
    icon: Plus, 
    label: t('navigation.publish'), 
    path: '/publicar-produto', 
    isAction: true 
  }

  // Itens de navegação (7 itens no total)
  const navItems = [
    { icon: Home, label: t('navigation.home'), path: '/app' },
    isAdmin
      ? { icon: LayoutDashboard, label: 'Admin', path: '/admindashboard' }
      : { icon: Map, label: t('navigation.map'), path: '/mapa' },
    { icon: MessageSquare, label: t('navigation.messages'), path: '/listamensagens', badge: unreadMessages },
    publishItem, // Posição central (4 de 7)
    { icon: Bell, label: t('navigation.notifications'), path: '/notificacoes', badge: unreadNotifications },
    { icon: BarChart3, label: 'Mercado', path: '/mercado' }, // Rota corrigida para /mercado
    { icon: User, label: t('navigation.profile'), path: '/perfil' },
  ]

  const isActive = (path: string) => location.pathname === path

  return (
    <>
      {/* Spacer */}
      <div style={{ height: 80 }}/>

      <nav style={{
        position:'fixed', bottom: 15, left: 8, right: 8, zIndex: 50,
        background: B.glass,
        backdropFilter: 'blur(20px)',
        border: `1px solid ${B.silver}`,
        borderRadius: 24,
        padding: '6px 4px',
        boxShadow: `0 12px 32px ${B.shadow}`,
        maxWidth: 650,
        margin: '0 auto'
      }}>
        <div style={{
          display:'flex',
          justifyContent: 'space-around',
          alignItems: 'center',
        }}>
          {navItems.map((item) => {
            const active = isActive(item.path)
            const isAction = (item as any).isAction

            return (
              <button
                key={item.path}
                onClick={() => navigate(item.path)}
                style={{
                  display:'flex', flexDirection:'column', alignItems:'center',
                  gap: 2, padding: '6px 2px', border:'none', cursor:'pointer',
                  borderRadius: 12, background: isAction ? B.brand : 'transparent',
                  transition:'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                  position:'relative',
                  flex: 1,
                  minWidth: 0,
                  ...(isAction ? {
                    boxShadow: `0 6px 12px rgba(27, 138, 61, 0.25)`,
                    transform: active ? 'scale(1.05)' : 'scale(1)',
                    padding: '8px 4px',
                  } : {}),
                }}
              >
                {/* Active Indicator Dot */}
                {active && !isAction && (
                  <div style={{
                    position:'absolute', top: -2, width: 3, height: 3, 
                    borderRadius: '50%', background: B.brand,
                  }}/>
                )}

                <div style={{ position:'relative' }}>
                  <item.icon
                    size={isAction ? 18 : 20}
                    strokeWidth={active ? 2.5 : 2}
                    color={
                      isAction ? B.white :
                      active ? B.brand :
                      'rgba(10, 12, 11, 0.4)'
                    }
                    style={{ transition:'all 0.2s' }}
                  />
                  {(item as any).badge > 0 && (
                    <span style={{
                      position:'absolute', top: -4, right: -6,
                      minWidth: 14, height: 14, borderRadius: '50%',
                      background: B.brandLight,
                      border: `1px solid ${B.white}`,
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: 8, fontWeight: 800, color: B.white,
                    }}>
                      {(item as any).badge > 99 ? '99+' : (item as any).badge}
                    </span>
                  )}
                </div>

                <span style={{
                  fontSize: 8, fontWeight: active ? 700 : 500,
                  color: isAction ? B.white : active ? B.brand : 'rgba(10, 12, 11, 0.4)',
                  letterSpacing: '-0.02em',
                  transition: 'all 0.2s',
                  whiteSpace: 'nowrap',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  width: '100%',
                  textAlign: 'center'
                }}>
                  {item.label}
                </span>
              </button>
            )
          })}
        </div>
      </nav>
    </>
  )
}

export default BottomNavigation

import React, { useState } from 'react';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { ChevronDown } from 'lucide-react';

export interface Country {
  code: string;
  name: string;
  dialCode: string;
  flag: string;
}

export const countries: Country[] = [
  { code: 'AO', name: 'Angola', dialCode: '+244', flag: '🇦🇴' },
  { code: 'CD', name: 'RD Congo', dialCode: '+243', flag: '🇨🇩' },
  { code: 'ZA', name: 'África do Sul', dialCode: '+27', flag: '🇿🇦' },
  { code: 'GB', name: 'Reino Unido', dialCode: '+44', flag: '🇬🇧' },
];

interface CountryPhoneInputProps {
  value: string;
  onChange: (value: string) => void;
  selectedCountry: Country;
  onCountryChange: (country: Country) => void;
  placeholder?: string;
  required?: boolean;
}

export const CountryPhoneInput = ({
  value,
  onChange,
  selectedCountry,
  onCountryChange,
  placeholder = '900 000 000',
  required = false,
}: CountryPhoneInputProps) => {
  const [isOpen, setIsOpen] = useState(false);

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Remove non-numeric characters except for spaces
    const cleaned = e.target.value.replace(/[^\d\s]/g, '');
    onChange(cleaned);
  };

  const getFullPhoneNumber = () => {
    if (!value) return '';
    return `${selectedCountry.dialCode} ${value}`;
  };

  return (
    <div className="flex gap-2">
      <DropdownMenu open={isOpen} onOpenChange={setIsOpen}>
        <DropdownMenuTrigger asChild>
          <Button
            variant="outline"
            className="flex items-center gap-1.5 min-w-[130px] justify-between px-3"
            type="button"
          >
            <span className="text-xl leading-none">{selectedCountry.flag}</span>
            <span className="text-sm font-semibold">{selectedCountry.dialCode}</span>
            <ChevronDown className="h-4 w-4 opacity-50 ml-1" />
          </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="start" className="w-[220px]">
          {countries.map((country) => (
            <DropdownMenuItem
              key={country.code}
              onClick={() => {
                onCountryChange(country);
                setIsOpen(false);
              }}
              className="flex items-center gap-3 cursor-pointer"
            >
              <span className="text-xl leading-none">{country.flag}</span>
              <span className="flex-1 font-medium">{country.name}</span>
              <span className="text-muted-foreground text-sm">{country.dialCode}</span>
            </DropdownMenuItem>
          ))}
        </DropdownMenuContent>
      </DropdownMenu>
      
      <Input
        type="tel"
        value={value}
        onChange={handlePhoneChange}
        placeholder={placeholder}
        className="flex-1"
        required={required}
      />
    </div>
  );
};

export default CountryPhoneInput;

import { useState } from "react";
import { Button } from "./ui/button";
import { Card } from "./ui/card";
import { Input } from "./ui/input";
import { Label } from "./ui/label";
import { Textarea } from "./ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "./ui/select";
import { Calendar } from "./ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "./ui/popover";
import { Badge } from "./ui/badge";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { CalendarDays, Plus, Minus, AlertCircle, CheckCircle } from "lucide-react";
import { cn } from "@/lib/utils";

const OrderSystem = () => {
  const [selectedDate, setSelectedDate] = useState<Date>();
  const [orderItems, setOrderItems] = useState<any[]>([]);
  const [customerInfo, setCustomerInfo] = useState({
    company: "",
    contact: "",
    phone: "",
    email: "",
    address: "",
    notes: ""
  });

  const products = [
    { id: 1, name: "Arroz Branco Premium", price: 85000, unit: "saco 50kg", minQty: 100 },
    { id: 2, name: "Feijão Preto", price: 120000, unit: "saco 50kg", minQty: 50 },
    { id: 3, name: "Banana da Madeira", price: 45000, unit: "caixa 20kg", minQty: 80 },
    { id: 5, name: "Carne Bovina", price: 1800000, unit: "kg", minQty: 500 },
    { id: 6, name: "Milho em Grão", price: 65000, unit: "saco 50kg", minQty: 200 }
  ];

  const addToOrder = (product: any) => {
    const existingItem = orderItems.find(item => item.id === product.id);
    if (existingItem) {
      setOrderItems(orderItems.map(item => 
        item.id === product.id 
          ? { ...item, quantity: item.quantity + product.minQty }
          : item
      ));
    } else {
      setOrderItems([...orderItems, { ...product, quantity: product.minQty }]);
    }
  };

  const updateQuantity = (productId: number, newQuantity: number) => {
    const product = products.find(p => p.id === productId);
    if (product && newQuantity >= product.minQty) {
      setOrderItems(orderItems.map(item =>
        item.id === productId ? { ...item, quantity: newQuantity } : item
      ));
    }
  };

  const removeFromOrder = (productId: number) => {
    setOrderItems(orderItems.filter(item => item.id !== productId));
  };

  const calculateTotal = () => {
    return orderItems.reduce((total, item) => total + (item.price * item.quantity), 0);
  };

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat('pt-AO', {
      style: 'currency',
      currency: 'AOA',
      minimumFractionDigits: 0
    }).format(price);
  };

  const isMinimumMet = calculateTotal() >= 1000000;

  const handleSubmitOrder = () => {
    if (!isMinimumMet || !selectedDate || orderItems.length === 0) {
      return;
    }
    // Here you would typically send the order to your backend
    alert("Pedido enviado com sucesso! Entraremos em contato em breve.");
  };

  // Calculate date range (max 2 weeks from today)
  const today = new Date();
  const maxDate = new Date();
  maxDate.setDate(today.getDate() + 14);

  return (
    <section id="pedidos" className="py-16 lg:py-24 bg-background-secondary">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-12">
          <h2 className="text-3xl md:text-4xl font-bold text-foreground mb-4">
            Sistema de Pedidos
          </h2>
          <p className="text-xl text-muted-foreground max-w-3xl mx-auto">
            Selecione produtos, quantidades e agende sua entrega.
          </p>
        </div>

        <div className="grid lg:grid-cols-2 gap-12">
          {/* Product Selection */}
          <div>
            <h3 className="text-2xl font-semibold text-foreground mb-6">
              Selecionar Produtos
            </h3>
            
            <div className="space-y-4 mb-8">
              {products.map((product) => (
                <Card key={product.id} className="p-4 border-card-border">
                  <div className="flex items-center justify-between">
                    <div className="flex-1">
                      <h4 className="font-semibold text-foreground">{product.name}</h4>
                      <p className="text-sm text-muted-foreground">
                        {formatPrice(product.price)}/{product.unit} • Mín: {product.minQty}
                      </p>
                    </div>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => addToOrder(product)}
                    >
                      <Plus className="h-4 w-4" />
                      Adicionar
                    </Button>
                  </div>
                </Card>
              ))}
            </div>

            {/* Order Summary */}
            <Card className="p-6 border-card-border">
              <h4 className="text-xl font-semibold text-foreground mb-4">
                Resumo do Pedido
              </h4>
              
              {orderItems.length === 0 ? (
                <p className="text-muted-foreground text-center py-8">
                  Nenhum produto selecionado
                </p>
              ) : (
                <div className="space-y-4">
                  {orderItems.map((item) => (
                    <div key={item.id} className="flex items-center justify-between border-b border-border pb-3">
                      <div className="flex-1">
                        <p className="font-medium text-foreground">{item.name}</p>
                        <p className="text-sm text-muted-foreground">
                          {formatPrice(item.price)} × {item.quantity}
                        </p>
                      </div>
                      <div className="flex items-center gap-2">
                        <Button
                          variant="outline"
                          size="icon"
                          className="h-8 w-8"
                          onClick={() => updateQuantity(item.id, item.quantity - item.minQty)}
                          disabled={item.quantity <= item.minQty}
                        >
                          <Minus className="h-3 w-3" />
                        </Button>
                        <span className="w-12 text-center text-sm">{item.quantity}</span>
                        <Button
                          variant="outline"
                          size="icon"
                          className="h-8 w-8"
                          onClick={() => updateQuantity(item.id, item.quantity + item.minQty)}
                        >
                          <Plus className="h-3 w-3" />
                        </Button>
                        <Button
                          variant="outline"
                          size="icon"
                          className="h-8 w-8 ml-2"
                          onClick={() => removeFromOrder(item.id)}
                        >
                          ×
                        </Button>
                      </div>
                    </div>
                  ))}
                  
                  <div className="pt-4 border-t border-border">
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-lg font-semibold">Total:</span>
                      <span className="text-xl font-bold text-primary">
                        {formatPrice(calculateTotal())}
                      </span>
                    </div>
                    
                    <div className="flex items-center gap-2">
                      {isMinimumMet ? (
                        <>
                          <CheckCircle className="h-4 w-4 text-success" />
                          <Badge variant="default" className="bg-success text-success-foreground">
                            Valor mínimo atingido
                          </Badge>
                        </>
                      ) : (
                        <>
                          <AlertCircle className="h-4 w-4 text-warning" />
                          <Badge variant="outline" className="border-warning text-warning">
                            Faltam {formatPrice(1000000 - calculateTotal())}
                          </Badge>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              )}
            </Card>
          </div>

          {/* Order Form */}
          <div>
            <h3 className="text-2xl font-semibold text-foreground mb-6">
              Informações do Pedido
            </h3>
            
            <Card className="p-6 border-card-border">
              <div className="space-y-6">
                {/* Customer Information */}
                <div className="grid grid-cols-1 gap-4">
                  <div>
                    <Label htmlFor="company">Empresa *</Label>
                    <Input
                      id="company"
                      placeholder="Nome da sua empresa"
                      value={customerInfo.company}
                      onChange={(e) => setCustomerInfo({...customerInfo, company: e.target.value})}
                    />
                  </div>
                  
                  <div>
                    <Label htmlFor="contact">Nome do Contato *</Label>
                    <Input
                      id="contact"
                      placeholder="Seu nome completo"
                      value={customerInfo.contact}
                      onChange={(e) => setCustomerInfo({...customerInfo, contact: e.target.value})}
                    />
                  </div>
                  
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="phone">Telefone *</Label>
                      <Input
                        id="phone"
                        placeholder="+244 xxx xxx xxx"
                        value={customerInfo.phone}
                        onChange={(e) => setCustomerInfo({...customerInfo, phone: e.target.value})}
                      />
                    </div>
                    <div>
                      <Label htmlFor="email">Email *</Label>
                      <Input
                        id="email"
                        type="email"
                        placeholder="email@empresa.com"
                        value={customerInfo.email}
                        onChange={(e) => setCustomerInfo({...customerInfo, email: e.target.value})}
                      />
                    </div>
                  </div>
                  
                  <div>
                    <Label htmlFor="address">Endereço de Entrega *</Label>
                    <Textarea
                      id="address"
                      placeholder="Endereço completo para entrega"
                      value={customerInfo.address}
                      onChange={(e) => setCustomerInfo({...customerInfo, address: e.target.value})}
                    />
                  </div>
                </div>

                {/* Delivery Date */}
                <div>
                  <Label>Data de Entrega *</Label>
                  <Popover>
                    <PopoverTrigger asChild>
                      <Button
                        variant="outline"
                        className={cn(
                          "w-full justify-start text-left font-normal",
                          !selectedDate && "text-muted-foreground"
                        )}
                      >
                        <CalendarDays className="mr-2 h-4 w-4" />
                        {selectedDate ? format(selectedDate, "PPP", { locale: ptBR }) : "Selecione a data"}
                      </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-auto p-0">
                      <Calendar
                        mode="single"
                        selected={selectedDate}
                        onSelect={setSelectedDate}
                        disabled={(date) => date < today || date > maxDate}
                        initialFocus
                      />
                    </PopoverContent>
                  </Popover>
                  <p className="text-xs text-muted-foreground mt-1">
                    Máximo de 2 semanas após o pedido
                  </p>
                </div>

                {/* Notes */}
                <div>
                  <Label htmlFor="notes">Observações</Label>
                  <Textarea
                    id="notes"
                    placeholder="Instruções especiais ou observações sobre o pedido..."
                    value={customerInfo.notes}
                    onChange={(e) => setCustomerInfo({...customerInfo, notes: e.target.value})}
                  />
                </div>

                {/* Submit Button */}
                <Button
                  variant="hero"
                  size="lg"
                  className="w-full"
                  onClick={handleSubmitOrder}
                  disabled={!isMinimumMet || !selectedDate || orderItems.length === 0 || !customerInfo.company || !customerInfo.contact}
                >
                  Enviar Pedido
                </Button>
                
                {(!isMinimumMet || !selectedDate || orderItems.length === 0) && (
                  <p className="text-sm text-muted-foreground text-center">
                    Complete todas as informações obrigatórias para enviar o pedido
                  </p>
                )}
              </div>
            </Card>
          </div>
        </div>
      </div>
    </section>
  );
};

export default OrderSystem;

import React, { useState, useEffect, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import { toast } from "sonner";
import {
  Crown,
  Shield,
  ShieldCheck,
  ShieldX,
  Users,
  Package,
  ShoppingCart,
  MessageSquare,
  TrendingUp,
  BarChart3,
  UserCog,
  Search,
  RefreshCw,
  ChevronDown,
  ChevronUp,
  AlertTriangle,
  Sparkles,
  Headphones,
} from "lucide-react";
import { Input } from "@/components/ui/input";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription,
} from "@/components/ui/dialog";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";

// Permission definitions with metadata
const PERMISSIONS = [
  { 
    key: "manage_users", 
    label: "Gerenciar Usuários", 
    description: "Verificar e gerenciar perfis de usuários",
    icon: Users,
    color: "text-blue-500"
  },
  { 
    key: "manage_products", 
    label: "Gerenciar Produtos", 
    description: "Visualizar e moderar produtos publicados",
    icon: Package,
    color: "text-green-500"
  },
  { 
    key: "manage_orders", 
    label: "Gerenciar Pedidos", 
    description: "Visualizar e atualizar status de pedidos",
    icon: ShoppingCart,
    color: "text-amber-500"
  },
  { 
    key: "manage_support", 
    label: "Gerenciar Suporte", 
    description: "Responder mensagens de suporte",
    icon: MessageSquare,
    color: "text-purple-500"
  },
  { 
    key: "manage_sourcing", 
    label: "Gerenciar Sourcing", 
    description: "Gerenciar pedidos especiais de sourcing",
    icon: TrendingUp,
    color: "text-indigo-500"
  },
  { 
    key: "view_analytics", 
    label: "Ver Analytics", 
    description: "Acesso a dados de mercado e estatísticas",
    icon: BarChart3,
    color: "text-pink-500"
  },
  { 
    key: "manage_admins", 
    label: "Gerenciar Admins", 
    description: "Promover e gerenciar outros administradores (apenas Root)",
    icon: UserCog,
    color: "text-red-500"
  },
] as const;

type PermissionKey = typeof PERMISSIONS[number]["key"];

interface AdminUser {
  id: string;
  full_name: string;
  email: string | null;
  user_type: string | null;
  is_root_admin: boolean;
  is_super_root: boolean;
  permissions: PermissionKey[];
  created_at: string;
}

interface User {
  id: string;
  full_name: string;
  email?: string | null;
  user_type?: string | null;
  is_root_admin?: boolean;
  is_super_root?: boolean;
}

interface AdminManagementProps {
  currentUserId: string;
  isRootAdmin: boolean;
  isSuperRoot: boolean;
  hasManageAdminsPermission?: boolean;
  users: User[];
  onRefresh: () => void;
}

const AdminManagement: React.FC<AdminManagementProps> = ({
  currentUserId,
  isRootAdmin,
  isSuperRoot,
  hasManageAdminsPermission = false,
  users,
  onRefresh,
}) => {
  const [admins, setAdmins] = useState<AdminUser[]>([]);
  const [supportAgents, setSupportAgents] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [promoteDialogOpen, setPromoteDialogOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [selectedPermissions, setSelectedPermissions] = useState<PermissionKey[]>([]);
  const [editingAdmin, setEditingAdmin] = useState<AdminUser | null>(null);
  const [editPermissions, setEditPermissions] = useState<PermissionKey[]>([]);
  const [revokeDialogOpen, setRevokeDialogOpen] = useState(false);
  const [adminToRevoke, setAdminToRevoke] = useState<AdminUser | null>(null);
  const [promoteToRootDialogOpen, setPromoteToRootDialogOpen] = useState(false);
  const [userToPromoteRoot, setUserToPromoteRoot] = useState<AdminUser | null>(null);
  const [promoteToSupportAgentDialogOpen, setPromoteToSupportAgentDialogOpen] = useState(false);
  const [userToPromoteSupportAgent, setUserToPromoteSupportAgent] = useState<User | null>(null);
  const [revokeSupportAgentDialogOpen, setRevokeSupportAgentDialogOpen] = useState(false);
  const [agentToRevoke, setAgentToRevoke] = useState<User | null>(null);
  const fetchAdmins = useCallback(async () => {
    setLoading(true);
    try {
      // Get all roles
      const { data: allRoles, error: rolesError } = await supabase
        .from("user_roles")
        .select("user_id, role");

      if (rolesError) throw rolesError;

      // Separate admin roles and support agent roles
      const adminUserIds = (allRoles || []).filter(r => r.role === "admin").map((r) => r.user_id);
      const supportAgentUserIds = (allRoles || []).filter(r => r.role === "support_agent").map((r) => r.user_id);

      if (adminUserIds.length === 0) {
        setAdmins([]);
      } else {
        // Get user details for admins
        const { data: adminUsers, error: usersError } = await supabase
          .from("users")
          .select("id, full_name, email, user_type, is_root_admin, is_super_root, created_at")
          .in("id", adminUserIds);

        if (usersError) throw usersError;

        // Get permissions for each admin
        const { data: permissions, error: permError } = await supabase
          .from("admin_permissions")
          .select("user_id, permission")
          .in("user_id", adminUserIds);

        if (permError) throw permError;

        // Combine data
        const adminList: AdminUser[] = (adminUsers || []).map((user) => ({
          ...user,
          is_root_admin: user.is_root_admin || false,
          is_super_root: (user as any).is_super_root || false,
          permissions: (permissions || [])
            .filter((p) => p.user_id === user.id)
            .map((p) => p.permission as PermissionKey),
        }));

        // Sort: super roots first, then root admins, then by name
        adminList.sort((a, b) => {
          if (a.is_super_root && !b.is_super_root) return -1;
          if (!a.is_super_root && b.is_super_root) return 1;
          if (a.is_root_admin && !b.is_root_admin) return -1;
          if (!a.is_root_admin && b.is_root_admin) return 1;
          return a.full_name.localeCompare(b.full_name);
        });

        setAdmins(adminList);
      }

      // Fetch support agents
      if (supportAgentUserIds.length > 0) {
        const { data: agentUsers, error: agentError } = await supabase
          .from("users")
          .select("id, full_name, email, user_type")
          .in("id", supportAgentUserIds);

        if (!agentError && agentUsers) {
          setSupportAgents(agentUsers);
        }
      } else {
        setSupportAgents([]);
      }
    } catch (error) {
      console.error("Error fetching admins:", error);
      toast.error("Erro ao carregar administradores");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAdmins();
  }, [fetchAdmins]);

  const promoteToAdmin = async () => {
    if (!selectedUser || selectedPermissions.length === 0) {
      toast.error("Selecione pelo menos uma permissão");
      return;
    }

    try {
      // Add admin role
      const { error: roleError } = await supabase
        .from("user_roles")
        .insert({ user_id: selectedUser.id, role: "admin" });

      if (roleError && !roleError.message.includes("duplicate")) throw roleError;

      // Add permissions
      const permissionInserts = selectedPermissions.map((permission) => ({
        user_id: selectedUser.id,
        permission,
        granted_by: currentUserId,
      }));

      const { error: permError } = await supabase
        .from("admin_permissions")
        .insert(permissionInserts);

      if (permError) throw permError;

      toast.success(`${selectedUser.full_name} promovido a sub-admin!`);
      setPromoteDialogOpen(false);
      setSelectedUser(null);
      setSelectedPermissions([]);
      fetchAdmins();
      onRefresh();
    } catch (error) {
      console.error("Error promoting user:", error);
      toast.error("Erro ao promover usuário");
    }
  };

  const updatePermissions = async () => {
    if (!editingAdmin) return;

    try {
      // Delete existing permissions
      const { error: deleteError } = await supabase
        .from("admin_permissions")
        .delete()
        .eq("user_id", editingAdmin.id);

      if (deleteError) throw deleteError;

      // Insert new permissions
      if (editPermissions.length > 0) {
        const permissionInserts = editPermissions.map((permission) => ({
          user_id: editingAdmin.id,
          permission,
          granted_by: currentUserId,
        }));

        const { error: insertError } = await supabase
          .from("admin_permissions")
          .insert(permissionInserts);

        if (insertError) throw insertError;
      }

      toast.success("Permissões atualizadas!");
      setEditingAdmin(null);
      setEditPermissions([]);
      fetchAdmins();
    } catch (error) {
      console.error("Error updating permissions:", error);
      toast.error("Erro ao atualizar permissões");
    }
  };

  const revokeAdmin = async () => {
    if (!adminToRevoke) return;

    try {
      // Remove admin role
      const { error: roleError } = await supabase
        .from("user_roles")
        .delete()
        .eq("user_id", adminToRevoke.id)
        .eq("role", "admin");

      if (roleError) throw roleError;

      // Remove all permissions
      const { error: permError } = await supabase
        .from("admin_permissions")
        .delete()
        .eq("user_id", adminToRevoke.id);

      if (permError) throw permError;

      toast.success(`Privilégios de admin removidos de ${adminToRevoke.full_name}`);
      setRevokeDialogOpen(false);
      setAdminToRevoke(null);
      fetchAdmins();
      onRefresh();
    } catch (error) {
      console.error("Error revoking admin:", error);
      toast.error("Erro ao revogar privilégios");
    }
  };

  const promoteToRoot = async () => {
    if (!userToPromoteRoot) return;

    try {
      // Update user to be root admin
      const { error: updateError } = await supabase
        .from("users")
        .update({ is_root_admin: true })
        .eq("id", userToPromoteRoot.id);

      if (updateError) throw updateError;

      toast.success(`${userToPromoteRoot.full_name} promovido a Root Admin!`);
      setPromoteToRootDialogOpen(false);
      setUserToPromoteRoot(null);
      fetchAdmins();
      onRefresh();
    } catch (error) {
      console.error("Error promoting to root:", error);
      toast.error("Erro ao promover a Root Admin");
    }
  };

  const promoteToSuperRoot = async (admin: AdminUser) => {
    try {
      const { error } = await supabase
        .from("users")
        .update({ is_super_root: true })
        .eq("id", admin.id);

      if (error) throw error;

      toast.success(`${admin.full_name} promovido a Super Root!`);
      fetchAdmins();
      onRefresh();
    } catch (error) {
      console.error("Error promoting to super root:", error);
      toast.error("Erro ao promover a Super Root");
    }
  };

  const demoteFromRoot = async (admin: AdminUser) => {
    try {
      const { error } = await supabase
        .from("users")
        .update({ is_root_admin: false, is_super_root: false })
        .eq("id", admin.id);

      if (error) throw error;

      toast.success(`${admin.full_name} rebaixado de Root Admin!`);
      fetchAdmins();
      onRefresh();
    } catch (error) {
      console.error("Error demoting from root:", error);
      toast.error("Erro ao rebaixar de Root Admin");
    }
  };

  // Promote to Support Agent
  const promoteToSupportAgent = async () => {
    if (!userToPromoteSupportAgent) return;

    try {
      const { error } = await supabase
        .from("user_roles")
        .insert({ user_id: userToPromoteSupportAgent.id, role: "support_agent" });

      if (error && !error.message.includes("duplicate")) throw error;

      toast.success(`${userToPromoteSupportAgent.full_name} promovido a Assistente de Atendimento!`);
      setPromoteToSupportAgentDialogOpen(false);
      setUserToPromoteSupportAgent(null);
      fetchAdmins();
      onRefresh();
    } catch (error) {
      console.error("Error promoting to support agent:", error);
      toast.error("Erro ao promover a Assistente de Atendimento");
    }
  };

  // Revoke Support Agent role
  const revokeSupportAgent = async () => {
    if (!agentToRevoke) return;

    try {
      const { error } = await supabase
        .from("user_roles")
        .delete()
        .eq("user_id", agentToRevoke.id)
        .eq("role", "support_agent");

      if (error) throw error;

      toast.success(`${agentToRevoke.full_name} removido de Assistente de Atendimento`);
      setRevokeSupportAgentDialogOpen(false);
      setAgentToRevoke(null);
      fetchAdmins();
      onRefresh();
    } catch (error) {
      console.error("Error revoking support agent:", error);
      toast.error("Erro ao revogar Assistente de Atendimento");
    }
  };

  const nonAdminUsers = users.filter(
    (u) => !admins.find((a) => a.id === u.id)
  );

  // Get agents (user_type === 'agente') that are not already support agents
  const availableAgents = users.filter(
    (u) => u.user_type === "agente" && !supportAgents.find((a) => a.id === u.id)
  );

  const filteredNonAdminUsers = nonAdminUsers.filter(
    (u) =>
      u.full_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (u.email || "").toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Allow access for root admins or users with manage_admins permission
  const canManageAdmins = isRootAdmin || hasManageAdminsPermission;

  if (!canManageAdmins) {
    return (
      <Card className="border-0 shadow-sm">
        <CardContent className="py-12 text-center">
          <Shield className="h-12 w-12 mx-auto mb-4 text-gray-300" />
          <p className="text-gray-500">Você não tem permissão para gerenciar administradores</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <Card className="border-0 shadow-sm bg-gradient-to-r from-primary/10 to-primary/5">
        <CardContent className="py-6">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-primary/20 rounded-xl">
              <Crown className="h-8 w-8 text-primary" />
            </div>
            <div>
              <h2 className="text-xl font-bold">Gerenciamento de Administradores</h2>
              <p className="text-sm text-muted-foreground">
                Como Root Admin, você pode promover sub-admins e definir suas permissões
              </p>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Current Admins */}
      <Card className="border-0 shadow-sm">
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle className="text-base font-semibold flex items-center gap-2">
              <Shield className="h-5 w-5 text-primary" /> Administradores Ativos ({admins.length})
            </CardTitle>
            <CardDescription>
              Gerencie as permissões de cada administrador
            </CardDescription>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" size="sm" onClick={fetchAdmins}>
              <RefreshCw className="h-4 w-4 mr-1" /> Atualizar
            </Button>
            <Button size="sm" onClick={() => setPromoteDialogOpen(true)}>
              <UserCog className="h-4 w-4 mr-1" /> Promover Novo Admin
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="flex items-center justify-center py-12">
              <RefreshCw className="h-6 w-6 animate-spin text-primary" />
            </div>
          ) : admins.length === 0 ? (
            <div className="text-center py-12 text-gray-500">
              <Shield className="h-12 w-12 mx-auto mb-4 text-gray-300" />
              <p>Nenhum administrador encontrado</p>
            </div>
          ) : (
            <Accordion type="single" collapsible className="space-y-3">
              {admins.map((admin) => (
                <AccordionItem
                  key={admin.id}
                  value={admin.id}
                  className="border rounded-xl px-4 bg-white shadow-sm"
                >
                  <AccordionTrigger className="hover:no-underline py-4">
                    <div className="flex items-center gap-3 flex-1">
                      <div className={`p-2 rounded-lg ${admin.is_super_root ? "bg-gradient-to-br from-purple-100 to-amber-100" : admin.is_root_admin ? "bg-amber-100" : "bg-primary/10"}`}>
                        {admin.is_super_root ? (
                          <Sparkles className="h-5 w-5 text-purple-600" />
                        ) : admin.is_root_admin ? (
                          <Crown className="h-5 w-5 text-amber-600" />
                        ) : (
                          <Shield className="h-5 w-5 text-primary" />
                        )}
                      </div>
                      <div className="text-left">
                        <div className="flex items-center gap-2 flex-wrap">
                          <span className="font-medium">{admin.full_name}</span>
                          {admin.is_super_root && (
                            <Badge className="bg-gradient-to-r from-purple-500 to-amber-500 text-white text-xs">Super Root</Badge>
                          )}
                          {admin.is_root_admin && !admin.is_super_root && (
                            <Badge className="bg-amber-100 text-amber-700 text-xs">Root Admin</Badge>
                          )}
                          {admin.id === currentUserId && (
                            <Badge variant="outline" className="text-xs">Você</Badge>
                          )}
                        </div>
                        <span className="text-sm text-gray-500">{admin.email || "Sem email"}</span>
                      </div>
                    </div>
                    <div className="flex items-center gap-2 mr-4">
                      <Badge variant="outline" className="text-xs">
                        {admin.is_root_admin ? "Todas" : admin.permissions.length} permissões
                      </Badge>
                    </div>
                  </AccordionTrigger>
                  <AccordionContent className="pb-4">
                    <div className="space-y-4">
                      {/* Permission List */}
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                        {PERMISSIONS.map((perm) => {
                          const Icon = perm.icon;
                          const hasPermission = admin.is_root_admin || admin.permissions.includes(perm.key);
                          const isManageAdmins = perm.key === "manage_admins";
                          
                          return (
                            <div
                              key={perm.key}
                              className={`flex items-center gap-3 p-3 rounded-lg border ${
                                hasPermission 
                                  ? "bg-primary/5 border-primary/20" 
                                  : "bg-gray-50 border-gray-100"
                              }`}
                            >
                              <Icon className={`h-5 w-5 ${hasPermission ? perm.color : "text-gray-400"}`} />
                              <div className="flex-1 min-w-0">
                                <p className={`text-sm font-medium ${hasPermission ? "text-gray-900" : "text-gray-500"}`}>
                                  {perm.label}
                                  {isManageAdmins && (
                                    <span className="ml-1 text-xs text-amber-600">(Root)</span>
                                  )}
                                </p>
                                <p className="text-xs text-gray-500 truncate">{perm.description}</p>
                              </div>
                              {hasPermission ? (
                                <ShieldCheck className="h-5 w-5 text-primary flex-shrink-0" />
                              ) : (
                                <ShieldX className="h-5 w-5 text-gray-300 flex-shrink-0" />
                              )}
                            </div>
                          );
                        })}
                      </div>

                      {/* Actions */}
                      {!admin.is_root_admin && admin.id !== currentUserId && (
                        <div className="flex gap-2 pt-2 border-t">
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => {
                              setEditingAdmin(admin);
                              setEditPermissions([...admin.permissions]);
                            }}
                          >
                            <UserCog className="h-4 w-4 mr-1" /> Editar Permissões
                          </Button>
                          <Button
                            variant="outline"
                            size="sm"
                            className="text-red-600 hover:text-red-700 hover:bg-red-50"
                            onClick={() => {
                              setAdminToRevoke(admin);
                              setRevokeDialogOpen(true);
                            }}
                          >
                            <ShieldX className="h-4 w-4 mr-1" /> Revogar Admin
                          </Button>
                        </div>
                      )}

                      {/* Root Admin Actions - Only Super Root can modify other roots */}
                      {admin.is_root_admin && !admin.is_super_root && admin.id !== currentUserId && isSuperRoot && (
                        <div className="flex flex-wrap gap-2 pt-2 border-t">
                          <Button
                            variant="outline"
                            size="sm"
                            className="text-purple-600 hover:text-purple-700 hover:bg-purple-50"
                            onClick={() => promoteToSuperRoot(admin)}
                          >
                            <Sparkles className="h-4 w-4 mr-1" /> Promover a Super Root
                          </Button>
                          <Button
                            variant="outline"
                            size="sm"
                            className="text-red-600 hover:text-red-700 hover:bg-red-50"
                            onClick={() => demoteFromRoot(admin)}
                          >
                            <ShieldX className="h-4 w-4 mr-1" /> Rebaixar de Root
                          </Button>
                        </div>
                      )}

                      {/* Sub-admin actions - Promote to root */}
                      {!admin.is_root_admin && admin.id !== currentUserId && isSuperRoot && (
                        <div className="pt-2 border-t">
                          <Button
                            variant="outline"
                            size="sm"
                            className="text-amber-600 hover:text-amber-700 hover:bg-amber-50"
                            onClick={() => {
                              setUserToPromoteRoot(admin);
                              setPromoteToRootDialogOpen(true);
                            }}
                          >
                            <Crown className="h-4 w-4 mr-1" /> Promover a Root Admin
                          </Button>
                        </div>
                      )}

                      {admin.is_root_admin && !isSuperRoot && (
                        <p className="text-xs text-amber-600 flex items-center gap-1 pt-2 border-t">
                          <Crown className="h-4 w-4" />
                          Administradores Root têm acesso total. Apenas Super Roots podem modificá-los.
                        </p>
                      )}

                      {admin.is_super_root && (
                        <p className="text-xs text-purple-600 flex items-center gap-1 pt-2 border-t">
                          <Sparkles className="h-4 w-4" />
                          Super Root - Nível máximo de acesso com poder de gerenciar outros roots
                        </p>
                      )}
                    </div>
                  </AccordionContent>
                </AccordionItem>
              ))}
            </Accordion>
          )}
        </CardContent>
      </Card>

      {/* Support Agents Section */}
      <Card className="border-0 shadow-sm">
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle className="text-base font-semibold flex items-center gap-2">
              <Headphones className="h-5 w-5 text-green-600" /> Assistentes de Atendimento ({supportAgents.length})
            </CardTitle>
            <CardDescription>
              Funcionários da AgriLink que auxiliam usuários e gerenciam entregas
            </CardDescription>
          </div>
          <Button 
            size="sm" 
            variant="outline"
            className="border-green-200 text-green-700 hover:bg-green-50"
            onClick={() => setPromoteToSupportAgentDialogOpen(true)}
          >
            <Headphones className="h-4 w-4 mr-1" /> Promover Assistente
          </Button>
        </CardHeader>
        <CardContent>
          {supportAgents.length === 0 ? (
            <div className="text-center py-12 text-gray-500">
              <Headphones className="h-12 w-12 mx-auto mb-4 text-gray-300" />
              <p>Nenhum assistente de atendimento</p>
              <p className="text-sm mt-1">Promova agentes para que trabalhem como assistentes</p>
            </div>
          ) : (
            <div className="space-y-3">
              {supportAgents.map((agent) => (
                <div
                  key={agent.id}
                  className="flex items-center justify-between p-4 rounded-xl border bg-green-50/50 border-green-100"
                >
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-green-100 rounded-lg">
                      <Headphones className="h-5 w-5 text-green-600" />
                    </div>
                    <div>
                      <p className="font-medium">{agent.full_name}</p>
                      <p className="text-sm text-muted-foreground">{agent.email || "Sem email"}</p>
                    </div>
                    <Badge className="bg-green-100 text-green-700">
                      Assistente
                    </Badge>
                  </div>
                  <Button
                    variant="outline"
                    size="sm"
                    className="text-red-600 hover:text-red-700 hover:bg-red-50"
                    onClick={() => {
                      setAgentToRevoke(agent);
                      setRevokeSupportAgentDialogOpen(true);
                    }}
                  >
                    <ShieldX className="h-4 w-4 mr-1" /> Revogar
                  </Button>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Promote User Dialog */}
      <Dialog open={promoteDialogOpen} onOpenChange={setPromoteDialogOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <UserCog className="h-5 w-5 text-primary" /> Promover Novo Sub-Admin
            </DialogTitle>
            <DialogDescription>
              Selecione um usuário e defina suas permissões de administrador
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4">
            {/* User Selection */}
            <div>
              <label className="text-sm font-medium text-gray-700 mb-2 block">Selecionar Usuário</label>
              <div className="relative mb-2">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
                <Input
                  placeholder="Buscar por nome ou email..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-9"
                />
              </div>
              <div className="max-h-40 overflow-y-auto border rounded-lg">
                {filteredNonAdminUsers.length === 0 ? (
                  <p className="text-sm text-gray-500 p-3 text-center">
                    Nenhum usuário disponível
                  </p>
                ) : (
                  filteredNonAdminUsers.slice(0, 10).map((user) => (
                    <button
                      key={user.id}
                      onClick={() => setSelectedUser(user)}
                      className={`w-full text-left px-3 py-2 hover:bg-gray-50 flex items-center gap-3 border-b last:border-0 ${
                        selectedUser?.id === user.id ? "bg-primary/10" : ""
                      }`}
                    >
                      <div className="flex-1 min-w-0">
                        <p className="font-medium text-sm truncate">{user.full_name}</p>
                        <p className="text-xs text-gray-500 truncate">{user.email || "Sem email"}</p>
                      </div>
                      <Badge variant="outline" className="text-xs capitalize">{user.user_type || "user"}</Badge>
                    </button>
                  ))
                )}
              </div>
              {selectedUser && (
                <div className="mt-2 p-2 bg-primary/10 rounded-lg flex items-center gap-2">
                  <ShieldCheck className="h-4 w-4 text-primary" />
                  <span className="text-sm font-medium">Selecionado: {selectedUser.full_name}</span>
                </div>
              )}
            </div>

            {/* Permission Selection */}
            <div>
              <label className="text-sm font-medium text-gray-700 mb-2 block">Permissões</label>
              <div className="space-y-2">
                {PERMISSIONS.filter((p) => p.key !== "manage_admins").map((perm) => {
                  const Icon = perm.icon;
                  const isSelected = selectedPermissions.includes(perm.key);
                  
                  return (
                    <button
                      key={perm.key}
                      onClick={() => {
                        setSelectedPermissions((prev) =>
                          isSelected
