import { useEffect, useRef, useState, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';

interface WorkSessionStats {
  totalSessions: number;
  totalMinutes: number;
  avgSessionMinutes: number;
}

export const useWorkSession = (userId: string | null, isSupportAgent: boolean) => {
  const [sessionId, setSessionId] = useState<string | null>(null);
  const [sessionStartTime, setSessionStartTime] = useState<Date | null>(null);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const [stats, setStats] = useState<WorkSessionStats | null>(null);
  const intervalRef = useRef<NodeJS.Timeout | null>(null);

  // Start a work session
  const startSession = useCallback(async () => {
    if (!userId || !isSupportAgent || sessionId) return;

    try {
      const { data, error } = await supabase
        .from('work_sessions')
        .insert({
          user_id: userId,
          started_at: new Date().toISOString(),
          is_active: true
        })
        .select('id')
        .single();

      if (error) throw error;

      setSessionId(data.id);
      setSessionStartTime(new Date());
      setElapsedSeconds(0);

      // Start the timer
      intervalRef.current = setInterval(() => {
        setElapsedSeconds(prev => prev + 1);
      }, 1000);

    } catch (error) {
      console.error('Error starting work session:', error);
    }
  }, [userId, isSupportAgent, sessionId]);

  // End a work session
  const endSession = useCallback(async () => {
    if (!sessionId) return;

    try {
      const { error } = await supabase
        .from('work_sessions')
        .update({
          ended_at: new Date().toISOString(),
          is_active: false
        })
        .eq('id', sessionId);

      if (error) throw error;

      // Stop the timer
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }

      setSessionId(null);
      setSessionStartTime(null);
      setElapsedSeconds(0);

    } catch (error) {
      console.error('Error ending work session:', error);
    }
  }, [sessionId]);

  // Fetch session stats
  const fetchStats = useCallback(async () => {
    if (!userId) return;

    try {
      const { data, error } = await supabase
        .rpc('get_work_session_stats', { p_user_id: userId });

      if (error) throw error;

      if (data && data[0]) {
        setStats({
          totalSessions: data[0].total_sessions || 0,
          totalMinutes: data[0].total_minutes || 0,
          avgSessionMinutes: data[0].avg_session_minutes || 0
        });
      }
    } catch (error) {
      console.error('Error fetching work session stats:', error);
    }
  }, [userId]);

  // Auto-start session when support agent logs in
  useEffect(() => {
    if (userId && isSupportAgent) {
      startSession();
      fetchStats();
    }

    // Cleanup on unmount or logout
    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
      }
    };
  }, [userId, isSupportAgent]);

  // End session on page unload
  useEffect(() => {
    const handleBeforeUnload = () => {
      if (sessionId) {
        // Use sendBeacon for reliable session end
        const url = `${import.meta.env.VITE_SUPABASE_URL || 'https://oqcrfqtlfqwrxxmsjpaf.supabase.co'}/rest/v1/work_sessions?id=eq.${sessionId}`;
        const body = JSON.stringify({
          ended_at: new Date().toISOString(),
          is_active: false
        });
        
        navigator.sendBeacon(url, body);
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [sessionId]);

  // Format elapsed time
  const formatElapsedTime = () => {
    const hours = Math.floor(elapsedSeconds / 3600);
    const minutes = Math.floor((elapsedSeconds % 3600) / 60);
    const seconds = elapsedSeconds % 60;

    return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
  };

  return {
    sessionId,
    sessionStartTime,
    elapsedSeconds,
    elapsedTimeFormatted: formatElapsedTime(),
    stats,
    startSession,
    endSession,
    fetchStats,
    isSessionActive: !!sessionId
  };
};

import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';

import ptTranslations from './locales/pt.json';
import enTranslations from './locales/en.json';
import frTranslations from './locales/fr.json';

// Map country codes to languages
export const countryToLanguage: Record<string, string> = {
  'AO': 'pt', // Angola - Portuguese
  'CD': 'fr', // DR Congo - French
  'ZA': 'en', // South Africa - English
  'GB': 'en', // UK - English
};

// Supported languages
const supportedLanguages = ['pt', 'en', 'fr'];

// Detect browser language
const detectBrowserLanguage = (): string => {
  try {
    const browserLang = navigator.language || (navigator as any).userLanguage;
    const langCode = browserLang?.split('-')[0]?.toLowerCase();
    
    if (langCode && supportedLanguages.includes(langCode)) {
      return langCode;
    }
    return 'pt'; // Default to Portuguese
  } catch {
    return 'pt';
  }
};

// Get saved language or detect from browser
const getSavedLanguage = () => {
  try {
    const saved = localStorage.getItem('orbislink_language');
    if (saved && supportedLanguages.includes(saved)) {
      return saved;
    }
    // No saved language, detect from browser
    return detectBrowserLanguage();
  } catch {
    return 'pt';
  }
};

i18n
  .use(initReactI18next)
  .init({
    resources: {
      pt: { translation: ptTranslations },
      en: { translation: enTranslations },
      fr: { translation: frTranslations },
    },
    lng: getSavedLanguage(),
    fallbackLng: 'pt',
    interpolation: {
      escapeValue: false,
    },
  });

// Function to change language and persist it
export const changeLanguage = (countryCode: string) => {
  const lang = countryToLanguage[countryCode] || 'pt';
  i18n.changeLanguage(lang);
  localStorage.setItem('orbislink_language', lang);
  localStorage.setItem('orbislink_country', countryCode);
};

export const getSavedCountry = () => {
  try {
    return localStorage.getItem('orbislink_country') || 'AO';
  } catch {
    return 'AO';
  }
};

