              style={{
                flex:2, height:42, borderRadius:10, border:'none',
                background:`linear-gradient(135deg, ${T.g500}, ${T.g700})`,
                cursor:'pointer', fontSize:13, fontWeight:800, color: T.white,
                display:'flex', alignItems:'center', justifyContent:'center', gap:8,
                boxShadow:`0 4px 16px rgba(45,125,58,0.3)`,
                opacity: (isSubmitting || !orderData.location.trim() || orderData.quantity < 1) ? 0.5 : 1,
                transition:'all 0.2s',
              }}
              onMouseEnter={e => { if (!(isSubmitting || !orderData.location.trim() || orderData.quantity < 1)) { (e.currentTarget as HTMLElement).style.transform = 'translateY(-1px)'; (e.currentTarget as HTMLElement).style.boxShadow = `0 6px 24px rgba(45,125,58,0.4)` } }}
              onMouseLeave={e => { (e.currentTarget as HTMLElement).style.transform = 'translateY(0)'; (e.currentTarget as HTMLElement).style.boxShadow = `0 4px 16px rgba(45,125,58,0.3)` }}
            >
              {isSubmitting ? (
                <>
                  <span style={{ width:14, height:14, borderRadius:'50%', border:'2px solid rgba(255,255,255,0.3)', borderTopColor:'#fff', animation:'spin 0.8s linear infinite' }}/>
                  A processar...
                </>
              ) : (
                <><ShoppingCart size={15}/> Confirmar Encomenda</>
              )}
            </button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Processing overlay */}
      {isSubmitting && (
        <div style={{ position:'fixed', inset:0, zIndex:9999, background:'rgba(13,43,18,0.75)', backdropFilter:'blur(10px)', display:'flex', alignItems:'center', justifyContent:'center' }}>
          <div style={{ background: T.white, padding:'36px 44px', borderRadius:20, display:'flex', flexDirection:'column', alignItems:'center', gap:18, border:`1px solid ${T.rule}`, boxShadow:`0 24px 80px rgba(0,0,0,0.2)` }}>
            <div style={{ position:'relative', width:52, height:52 }}>
              <div style={{ position:'absolute', inset:0, borderRadius:'50%', border:`2px solid ${T.gBorder}`, borderTopColor: T.g500, animation:'spin 0.9s linear infinite' }}/>
              <div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center' }}>
                <img src={orbisLinkLogo} alt="" style={{ width:24, height:24, objectFit:'contain' }}/>
              </div>
            </div>
            <div style={{ textAlign:'center' }}>
              <p style={{ fontFamily:"'Cormorant Garamond', Georgia, serif", fontSize:16, fontWeight:700, color: T.ink }}>A processar</p>
              <p style={{ fontSize:12, color: T.faint, marginTop:4 }}>Registando encomenda...</p>
            </div>
            <div style={{ width:200, height:2, borderRadius:99, background: T.g50, overflow:'hidden' }}>
              <div style={{ height:'100%', background:`linear-gradient(90deg, ${T.g500}, ${T.g400})`, animation:'progressBar 2s ease-in-out infinite', borderRadius:99 }}/>
            </div>
          </div>
        </div>
      )}

      {/* Map modal */}
      <Dialog open={mapModalOpen} onOpenChange={setMapModalOpen}>
        <DialogContent style={{ maxWidth:780, padding:0, overflow:'hidden', borderRadius:20, border:`1px solid ${T.rule}`, boxShadow:`0 24px 80px rgba(13,43,18,0.2)` }}>
          <div style={{ padding:'16px 22px', background: T.white, borderBottom:`1px solid ${T.rule}`, display:'flex', alignItems:'center', gap:12 }}>
            <div style={{ width:34, height:34, borderRadius:9, background: T.g50, border:`1px solid ${T.gBorder}`, display:'flex', alignItems:'center', justifyContent:'center' }}>
              <MapPin size={15} color={T.g600}/>
            </div>
            <div>
              <DialogTitle style={{ fontFamily:"'Cormorant Garamond', Georgia, serif", fontSize:16, fontWeight:700, color: T.ink, margin:0 }}>
                Localização do Fornecedor
              </DialogTitle>
              <DialogDescription style={{ fontSize:11, color: T.faint, marginTop:2 }}>
                {selectedProduct?.product_type} · {selectedProduct?.farmer_name}
              </DialogDescription>
            </div>
          </div>
          <div ref={mapContainerRef} style={{ width:'100%', height:440 }}/>
        </DialogContent>
      </Dialog>

      {/* ── Global keyframes ── */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:wght@600;700&family=DM+Sans:wght@400;500;600;700;800;900&display=swap');

        @keyframes spin        { to { transform: rotate(360deg) } }
        @keyframes shimmer     { 0%,100% { opacity:1 } 50% { opacity:0.4 } }
        @keyframes breathe     { 0%,100% { opacity:1; transform:scale(1) } 50% { opacity:0.4; transform:scale(0.7) } }
        @keyframes cardEnter   { from { opacity:0; transform:translateY(20px) } to { opacity:1; transform:translateY(0) } }
        @keyframes progressBar { 0% { width:0%; margin-left:0 } 60% { width:100%; margin-left:0 } 100% { width:0%; margin-left:100% } }
        @keyframes tickerScroll { 0% { transform:translateX(0) } 100% { transform:translateX(-50%) } }

        * { box-sizing: border-box; }

        @media (max-width: 640px) {
          #products-grid { padding-left: 14px !important; padding-right: 14px !important; }
        }
      `}</style>
    </div>
  )
}

export default AppHome

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ArrowLeft, Building2, Briefcase, History, FileText } from 'lucide-react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

import { CompanyHeader, CompanyTier, UserType } from '@/components/b2b/CompanyHeader';
import { TrustMetrics } from '@/components/b2b/TrustMetrics';
import { BuyerProfile } from '@/components/b2b/BuyerProfile';
import { SupplierPortfolio, PortfolioProduct } from '@/components/b2b/SupplierPortfolio';
import { AboutCompany } from '@/components/b2b/AboutCompany';
import { ActionButtons } from '@/components/b2b/ActionButtons';

import orbisLinkLogo from '@/assets/orbislink-logo.png';

interface CompanyData {
  id: string;
  name: string;
  logo?: string | null;
  sector: string;
  location: string;
  memberSince: string;
  isVerified: boolean;
  tier: CompanyTier;
  userType: UserType;
  description: string;
  foundedYear?: number;
  employees?: string;
  annualRevenue?: string;
  phone?: string;
}

const B2BProfile = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [companyData, setCompanyData] = useState<CompanyData | null>(null);
  const [products, setProducts] = useState<PortfolioProduct[]>([]);

  // Mock trust metrics (in production, these would come from aggregated data)
  const trustMetrics = {
    completedNegotiations: 127,
    averageRating: 4.8,
    totalReviews: 89,
    deliveryRate: 98,
    paymentRate: 100,
    responseTime: '< 2 horas',
    onTimeDelivery: 95,
    repeatBuyerRate: 72
  };

  // Mock buyer profile data
  const buyerProfileData = {
    categories: ['Cereais', 'Leguminosas', 'Frutas', 'Vegetais', 'Oleaginosas'],
    monthlyVolume: '50-100 ton',
    purchaseFrequency: 'Semanal',
    budgetRange: '10M - 50M Kz/mês',
    preferredIncoterms: ['FOB', 'CIF', 'DAP'],
    paymentTerms: ['30 dias', '60 dias', 'À vista com desconto']
  };

  // Mock supplier data
  const supplierData = {
    productionCapacity: '500 ton/mês',
    certifications: ['ISO 9001', 'HACCP', 'Global GAP', 'Orgânico'],
    logistics: ['Transporte próprio', 'Armazém refrigerado', 'Entrega nacional']
  };

  useEffect(() => {
    if (id) {
      if (user?.id === id) {
        navigate('/perfil', { replace: true });
        return;
      }
      fetchCompanyData();
    }
  }, [id, user, navigate]);

  const fetchCompanyData = async () => {
    try {
      setLoading(true);
      
      const { data: userData, error } = await supabase
        .from('users')
        .select('*')
        .eq('id', id)
        .single();

      if (error) throw error;

      // Determine tier based on some criteria (simplified for demo)
      const determineTier = (): CompanyTier => {
        if (userData.is_root_admin) return 'enterprise';
        if (userData.verified) return 'gold';
        return 'bronze';
      };

      setCompanyData({
        id: userData.id,
        name: userData.full_name,
        logo: userData.avatar_url,
        sector: userData.user_type === 'comprador' ? 'Agroindústria' : 'Produção Agrícola',
        location: `${userData.municipality_id}, ${userData.province_id}`,
        memberSince: new Date(userData.created_at).toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' }),
        isVerified: userData.verified || false,
        tier: determineTier(),
        userType: userData.user_type || 'comprador',
        description: `Empresa sediada em ${userData.province_id} com foco em operações de ${userData.user_type === 'comprador' ? 'aquisição e distribuição' : 'produção e fornecimento'} de produtos agrícolas de alta qualidade. Comprometida com práticas sustentáveis e parcerias de longo prazo.`,
        foundedYear: 2018,
        employees: '25-50',
        annualRevenue: '500M+ Kz',
        phone: userData.phone
      });

      // Fetch products if supplier
      if (userData.user_type !== 'comprador') {
        const { data: productsData } = await supabase
          .from('products')
          .select('*')
          .eq('user_id', id)
          .eq('status', 'active')
          .order('created_at', { ascending: false })
          .limit(10);

        if (productsData) {
          const portfolioProducts: PortfolioProduct[] = productsData.map((p, index) => ({
            id: p.id,
            name: p.product_type,
            sku: `SKU-${String(index + 1).padStart(4, '0')}`,
            unit: 'kg',
            moq: Math.min(p.quantity, 100),
            prices: [
              { minQty: 100, price: p.price },
              { minQty: 500, price: Math.round(p.price * 0.95) },
              { minQty: 1000, price: Math.round(p.price * 0.90) }
            ],
            stock: p.quantity,
            leadTime: '3-5 dias',
            photo: p.photos?.[0]
          }));
          setProducts(portfolioProducts);
        }
      }
    } catch (error) {
      console.error('Erro ao carregar perfil:', error);
      toast.error('Erro ao carregar perfil da empresa');
    } finally {
      setLoading(false);
    }
  };

  const handleStartChat = async () => {
    if (!user || !id) {
      toast.error('Faça login para iniciar uma conversa');
      return;
    }

    try {
      const { data: existingConv } = await supabase
        .from('conversations')
        .select('id')
        .or(`and(user_id.eq.${user.id},peer_user_id.eq.${id}),and(user_id.eq.${id},peer_user_id.eq.${user.id})`)
        .limit(1);

      if (existingConv && existingConv.length > 0) {
        navigate(`/messages/${existingConv[0].id}`);
        return;
      }

      const { data: newConv, error } = await supabase
        .from('conversations')
        .insert({
          user_id: user.id,
          peer_user_id: id,
          title: companyData?.name || 'Empresa',
          avatar: companyData?.logo,
          last_timestamp: new Date().toISOString(),
        })
        .select('id')
        .single();

      if (error) throw error;
      navigate(`/messages/${newConv.id}`);
    } catch (error) {
      console.error('Erro ao iniciar conversa:', error);
      toast.error('Erro ao iniciar conversa');
    }
  };

  const handleRFQ = () => {
    toast.info('Funcionalidade de RFQ em desenvolvimento');
  };

  const handleViewProduct = (productId: string) => {
    navigate(`/app`);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-[#0a1628]"></div>
      </div>
    );
  }

  if (!companyData) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-4">
        <p className="text-muted-foreground mb-4">Empresa não encontrada</p>
        <Button onClick={() => navigate(-1)}>Voltar</Button>
      </div>
    );
  }

  const isBuyer = companyData.userType === 'comprador';

  return (
    <div className="min-h-screen bg-white pb-24">
      {/* Header */}
      <header className="sticky top-0 z-20 bg-white border-b border-border px-4 py-3 flex items-center gap-4">
        <Button variant="ghost" size="icon" onClick={() => navigate(-1)}>
          <ArrowLeft className="h-5 w-5 text-[#0a1628]" />
        </Button>
        <img src={orbisLinkLogo} alt="OrbisLink" className="h-8" />
        <h1 className="text-lg font-semibold text-[#0a1628]">Perfil Institucional</h1>
      </header>

      {/* Company Header */}
      <CompanyHeader
        name={companyData.name}
        logo={companyData.logo}
        sector={companyData.sector}
        location={companyData.location}
        memberSince={companyData.memberSince}
        isVerified={companyData.isVerified}
        tier={companyData.tier}
        userType={companyData.userType}
      />

      {/* Main Content */}
      <div className="p-4 max-w-6xl mx-auto">
        <Tabs defaultValue="overview" className="w-full">
          <TabsList className="w-full grid grid-cols-4 mb-6 bg-gray-100">
            <TabsTrigger value="overview" className="text-xs sm:text-sm data-[state=active]:bg-white data-[state=active]:text-[#0a1628]">
              <Building2 className="h-4 w-4 mr-1 hidden sm:inline" />
              Visão Geral
            </TabsTrigger>
            <TabsTrigger value="commercial" className="text-xs sm:text-sm data-[state=active]:bg-white data-[state=active]:text-[#0a1628]">
              <Briefcase className="h-4 w-4 mr-1 hidden sm:inline" />
              {isBuyer ? 'Perfil Compra' : 'Portfólio'}
            </TabsTrigger>
            <TabsTrigger value="history" className="text-xs sm:text-sm data-[state=active]:bg-white data-[state=active]:text-[#0a1628]">
              <History className="h-4 w-4 mr-1 hidden sm:inline" />
              Histórico
            </TabsTrigger>
            <TabsTrigger value="documents" className="text-xs sm:text-sm data-[state=active]:bg-white data-[state=active]:text-[#0a1628]">
              <FileText className="h-4 w-4 mr-1 hidden sm:inline" />
              Documentos
            </TabsTrigger>
          </TabsList>

          {/* Overview Tab */}
          <TabsContent value="overview" className="space-y-6">
            <AboutCompany
              description={companyData.description}
              foundedYear={companyData.foundedYear}
              employees={companyData.employees}
              annualRevenue={companyData.annualRevenue}
            />
            
            <TrustMetrics {...trustMetrics} />
          </TabsContent>

          {/* Commercial Tab */}
          <TabsContent value="commercial" className="space-y-6">
            {isBuyer ? (
              <BuyerProfile {...buyerProfileData} />
            ) : (
              <SupplierPortfolio
                products={products}
                productionCapacity={supplierData.productionCapacity}
                certifications={supplierData.certifications}
                logistics={supplierData.logistics}
                onViewProduct={handleViewProduct}
              />
            )}
          </TabsContent>

          {/* History Tab */}
          <TabsContent value="history" className="space-y-6">
            <div className="text-center py-12 text-muted-foreground">
              <History className="h-12 w-12 mx-auto mb-4 opacity-30" />
              <p>Histórico de transações disponível em breve</p>
            </div>
          </TabsContent>

          {/* Documents Tab */}
          <TabsContent value="documents" className="space-y-6">
            <div className="text-center py-12 text-muted-foreground">
              <FileText className="h-12 w-12 mx-auto mb-4 opacity-30" />
              <p>Gestão de documentos disponível em breve</p>
            </div>
          </TabsContent>
        </Tabs>
      </div>

      {/* Fixed Action Buttons */}
      <ActionButtons
        onChat={handleStartChat}
        onRFQ={handleRFQ}
        phone={companyData.phone}
      />
    </div>
  );
};

export default B2BProfile;

import React, { useEffect, useState, useCallback, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarImage, AvatarFallback } from "@/components/ui/avatar";
import { useNavigate } from "react-router-dom";
import { useAuth } from "@/contexts/AuthContext";
import { Search, Plus, MessageSquare, UserPlus } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { useToast } from "@/hooks/use-toast";

// --- Branding Tokens ---
const T = {
  /* Greens */
  g900:   '#2c863b',
  g700:   '#1A5C24',
  g600:   '#2D7D3A',
  g500:   '#3D9A48',
  g400:   '#4CAF50',
  g100:   '#E8F5E9',
  g50:    '#F2FAF3',
  gBorder:'#C8E6CA',

  /* Earth */
  e700:   '#5C3317',
  e500:   '#7B4F2E',
  e300:   '#A0522D',
  ePale:  '#FDF5EE',
  eBorder:'#EDD9C6',

  /* Neutrals */
  ink:    '#111714',
  mid:    '#3D4D40',
  muted:  '#758A79',
  faint:  '#A8BAA9',
  canvas: '#F7F9F7',
  white:  '#FFFFFF',
  rule:   '#E5EDE6',

  /* Accents */
  gold:   '#B07D0A',
  goldL:  '#E5A020',

  /* Shadow */
  shadow: 'rgba(13,43,18,0.10)',
  shadowMd:'rgba(13,43,18,0.15)',
}

// --- Tipos ---

interface Conversation {
  id: string;
  title: string;
  last_message: string | null;
  last_timestamp: string;
  unread_count: number;
  avatar: string | null;
  participant_id: string;
}

interface UserProfile {
  id: string;
  full_name: string;
  avatar_url: string | null;
}

// --- Funções Auxiliares ---

const highlightText = (text: string, term: string) => {
  if (!term) return text;
  const escapedTerm = term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp(`(${escapedTerm})`, "gi");
  const parts = text.split(regex);
  
  return parts.map((part, i) =>
    regex.test(part) ? <strong key={i} style={{ color: T.g600 }}>{part}</strong> : part
  );
};

const debounce = (func: Function, delay = 300) => {
  let timer: NodeJS.Timeout;
  return (...args: any[]) => {
    clearTimeout(timer);
    timer = setTimeout(() => func(...args), delay);
  };
};

// --- Componente Principal ---

const ConversationsList = () => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { toast } = useToast();
  const navigate = useNavigate();

  const [searchTerm, setSearchTerm] = useState("");
  const [userResults, setUserResults] = useState<UserProfile[]>([]);
  const [allConversations, setAllConversations] = useState<Conversation[]>([]);
  const [loading, setLoading] = useState(false);
  const [newConversationOpen, setNewConversationOpen] = useState(false);
  const [newConvSearchTerm, setNewConvSearchTerm] = useState("");
  const [allUsers, setAllUsers] = useState<UserProfile[]>([]);

  const loadConversations = useCallback(async () => {
    if (!user) return;
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from("conversations")
        .select("*")
        .or(`user_id.eq.${user.id},participant_id.eq.${user.id}`)
        .order("last_timestamp", { ascending: false });

      if (error) throw error;
      setAllConversations((data as Conversation[]) || []);
    } catch (error) {
      console.error("Erro ao carregar conversas:", error);
      toast({
        title: t('common.error'),
        description: t('messages.noMessages'),
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  }, [user, toast, t]);

  useEffect(() => {
    loadConversations();
    if (!user) return;

    const channel = supabase
      .channel("conversations-updates")
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: "conversations",
          filter: `user_id=eq.${user.id},participant_id=eq.${user.id}`, 
        },
        () => {
          loadConversations();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user, loadConversations]);

  const search = useCallback(
    debounce(async (term: string) => {
      if (!user || term.trim() === "") {
        setUserResults([]);
        return;
      }
      setLoading(true);
      try {
        const { data: users, error: usersError } = await supabase
          .from("users")
          .select("id, full_name, avatar_url")
          .ilike("full_name", `%${term}%`)
          .neq("id", user.id)
          .limit(10);

        if (usersError) {
          console.error("Erro ao buscar usuários:", usersError);
        } else {
          setUserResults((users as UserProfile[]) || []);
        }
      } catch (err) {
        console.error("Erro na busca:", err);
        toast({
          title: t('common.error'),
          description: t('messages.noResults'),
          variant: "destructive"
        });
      }
      setLoading(false);
    }, 300),
    [user, toast, t]
  );

  useEffect(() => {
    search(searchTerm);
  }, [searchTerm, search]);

  const conversationResults = useMemo(() => {
    if (searchTerm.trim() === "") return allConversations;
    return allConversations.filter(conv =>
      conv.title.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [allConversations, searchTerm]);

  const startConversation = useCallback(async (
    participantId: string, 
    participantName: string, 
    participantAvatar: string | null
  ) => {
    if (!user) return;
    const { data: existingConv, error: searchError } = await supabase
      .from("conversations")
      .select("id")
      .or(`and(user_id.eq.${user.id},participant_id.eq.${participantId}),and(user_id.eq.${participantId},participant_id.eq.${user.id})`)
      .limit(1);

    if (searchError) {
      console.error("Erro ao buscar conversa existente:", searchError);
      toast({
        title: t('common.error'),
        description: t('messages.noResults'),
        variant: "destructive"
      });
      return;
    }

    if (existingConv && existingConv.length > 0) {
      navigate(`/messages/${existingConv[0].id}`);
      return;
    }

    try {
      const newConvData = {
        user_id: user.id,
        participant_id: participantId,
        title: participantName,
        avatar: participantAvatar,
        last_message: null,
        last_timestamp: new Date().toISOString(),
        unread_count: 0,
      };

      const { data: createdConv, error: createError } = await supabase
        .from("conversations")
        .insert([newConvData])
        .select("id")
        .single();

      if (createError) throw createError;
      navigate(`/messages/${createdConv.id}`);
    } catch (error) {
      console.error("Erro ao criar nova conversa:", error);
      toast({
        title: t('common.error'),
        description: t('messages.noResults'),
        variant: "destructive"
      });
    }
  }, [user, navigate, toast, t]);

  const formatTime = (timestamp: string) => {
    if (!timestamp) return "";
    const date = new Date(timestamp);
    const now = new Date();
    const diff = now.getTime() - date.getTime();
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (days === 0) {
      return date.toLocaleTimeString("pt-BR", { hour: "2-digit", minute: "2-digit" });
    } else if (days === 1) {
      return t('messages.yesterday');
    } else if (days < 7) {
      return `${days}${t('messages.daysAgo')}`;
    } else {
      return date.toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit" });
    }
  };

  const openNewConversationDialog = async () => {
    if (!user) return;
    setNewConversationOpen(true);
    setNewConvSearchTerm("");
    try {
      const { data: users, error } = await supabase
        .from("users")
        .select("id, full_name, avatar_url")
        .neq("id", user.id)
        .order("full_name", { ascending: true })
        .limit(50);
      
      if (error) {
        console.error("Erro ao buscar usuários:", error);
        toast({
          title: t('common.error'),
          description: t('messages.noUserFound'),
          variant: "destructive"
        });
      } else {
        setAllUsers((users as UserProfile[]) || []);
      }
    } catch (err) {
      console.error("Erro ao carregar usuários:", err);
    }
  };

  const filteredUsers = useMemo(() => {
    return allUsers.filter(usr =>
      usr.full_name.toLowerCase().includes(newConvSearchTerm.toLowerCase())
    );
  }, [allUsers, newConvSearchTerm]);

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center" style={{ backgroundColor: T.canvas }}>
        <p style={{ color: T.muted }}>{t('common.loading')}</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col" style={{ backgroundColor: T.canvas, color: T.ink }}>
      {/* Cabeçalho */}
      <header 
        className="sticky top-0 z-10 px-6 py-5 border-b shadow-sm backdrop-blur-md"
        style={{ 
          backgroundColor: 'rgba(247, 249, 247, 0.8)', 
          borderColor: T.rule 
        }}
      >
        <div className="flex items-center justify-between mb-5">
          <div>
            <h1 className="text-2xl font-bold tracking-tight" style={{ color: T.ink }}>
              {t('messages.title')}
            </h1>
            <p className="text-xs font-medium uppercase tracking-widest mt-1" style={{ color: T.muted }}>
              {allConversations.length} {t('messages.conversations').toLowerCase()}
            </p>
          </div>
          <Button
            onClick={openNewConversationDialog}
            className="rounded-full h-12 w-12 shadow-lg transition-transform hover:scale-105 active:scale-95"
            style={{ backgroundColor: T.g600, color: T.white }}
          >
            <Plus className="h-6 w-6" />
          </Button>
        </div>
        <div className="relative group">
          <Search 
            className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 transition-colors group-focus-within:text-g600" 
            style={{ color: T.faint }} 
          />
          <Input
            placeholder={t('messages.searchConversations')}
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-11 h-12 bg-white border-none rounded-xl shadow-sm focus-visible:ring-2"
            style={{ 
              '--tw-ring-color': T.gBorder,
              color: T.ink
            } as React.CSSProperties}
          />
        </div>
      </header>

      {/* Lista de Conversas */}
      <div className="flex-1 overflow-y-auto px-4 py-6 space-y-6">
        {loading && searchTerm.trim() !== "" && (
          <div className="flex justify-center py-4">
            <div className="animate-pulse text-sm font-medium" style={{ color: T.g600 }}>
              {t('messages.searching')}...
            </div>
          </div>
        )}

        {/* Resultados de Usuários */}
        {userResults.length > 0 && searchTerm.trim() !== "" && (
          <section className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] mb-3 px-2" style={{ color: T.muted }}>
              {t('messages.users')}
            </h2>
            <div className="space-y-2">
              {userResults.map((usr) => (
                <Card
                  key={usr.id}
                  onClick={() => startConversation(usr.id, usr.full_name, usr.avatar_url)}
                  className="border-none shadow-sm hover:shadow-md transition-all cursor-pointer overflow-hidden group"
                  style={{ backgroundColor: T.white }}
                >
                  <CardContent className="flex items-center gap-4 p-4">
                    <div className="relative">
                      <Avatar className="h-12 w-12 border-2 transition-transform group-hover:scale-105" style={{ borderColor: T.g50 }}>
                        <AvatarImage src={usr.avatar_url || "/default-avatar.png"} />
                        <AvatarFallback style={{ backgroundColor: T.g100, color: T.g700 }}>
                          {usr.full_name.charAt(0).toUpperCase()}
                        </AvatarFallback>
                      </Avatar>
                      <div className="absolute -bottom-1 -right-1 bg-white p-1 rounded-full shadow-sm">
                        <UserPlus className="h-3 w-3" style={{ color: T.g600 }} />
                      </div>
                    </div>
                    <div className="flex-1">
                      <p className="font-semibold text-sm" style={{ color: T.ink }}>
                        {highlightText(usr.full_name, searchTerm)}
                      </p>
                      <p className="text-xs mt-0.5" style={{ color: T.muted }}>
                        {t('messages.clickToStart')}
                      </p>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </section>
        )}

        {/* Lista de Conversas */}
        {conversationResults.length > 0 && (
          <section className="animate-in fade-in duration-500">
            {userResults.length > 0 && searchTerm.trim() !== "" && (
              <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] mb-3 mt-6 px-2" style={{ color: T.muted }}>
                {t('messages.conversations')}
              </h2>
            )}
            <div className="space-y-3">
              {conversationResults.map((conv) => (
                <Card
                  key={conv.id}
                  onClick={() => navigate(`/messages/${conv.id}`)}
                  className="border-none shadow-sm hover:shadow-md transition-all cursor-pointer group relative overflow-hidden"
                  style={{ backgroundColor: T.white }}
                >
                  {conv.unread_count > 0 && (
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: T.g500 }} />
                  )}
                  <CardContent className="flex items-center justify-between p-4">
                    <div className="flex items-center gap-4 flex-1 min-w-0">
                      <Avatar className="h-14 w-14 border-2 transition-transform group-hover:scale-105" style={{ borderColor: T.g50 }}>
                        <AvatarImage src={conv.avatar || "/default-avatar.png"} />
                        <AvatarFallback style={{ backgroundColor: T.ePale, color: T.e700 }}>
                          {conv.title.charAt(0).toUpperCase()}
                        </AvatarFallback>
                      </Avatar>
                      <div className="flex flex-col flex-1 min-w-0">
                        <div className="flex items-center justify-between mb-1">
                          <span className="font-bold text-[15px] truncate" style={{ color: T.ink }}>
                            {highlightText(conv.title, searchTerm)}
                          </span>
                          <span className="text-[10px] font-medium" style={{ color: T.faint }}>
                            {formatTime(conv.last_timestamp)}
                          </span>
                        </div>
                        <p className={`text-sm truncate ${conv.unread_count > 0 ? 'font-semibold' : 'font-normal'}`} 
                           style={{ color: conv.unread_count > 0 ? T.mid : T.muted }}>
                          {conv.last_message || t('messages.noMessageYet')}
                        </p>
                      </div>
                    </div>
                    {conv.unread_count > 0 && (
                      <div className="ml-4 flex-shrink-0">
                        <span 
                          className="flex items-center justify-center h-5 min-w-[20px] px-1.5 rounded-full text-[10px] font-black shadow-sm"
                          style={{ backgroundColor: T.g600, color: T.white }}
                        >
                          {conv.unread_count}
                        </span>
                      </div>
                    )}
                  </CardContent>
                </Card>
              ))}
            </div>
          </section>
        )}

        {/* Estados Vazios */}
        {!loading && searchTerm.trim() !== "" && userResults.length === 0 && conversationResults.length === 0 && (
          <div className="flex flex-col items-center justify-center py-20 text-center animate-in fade-in zoom-in-95">
            <div className="bg-white p-6 rounded-full shadow-sm mb-6">
              <Search className="h-10 w-10" style={{ color: T.faint }} />
            </div>
            <p className="font-bold text-lg" style={{ color: T.ink }}>{t('messages.noResults')}</p>
            <p className="text-sm mt-2 max-w-[200px]" style={{ color: T.muted }}>
              {t('messages.tryAnotherName')}
            </p>
          </div>
        )}

        {!loading && searchTerm.trim() === "" && conversationResults.length === 0 && (
          <div className="flex flex-col items-center justify-center py-20 text-center animate-in fade-in zoom-in-95">
            <div className="bg-white p-8 rounded-full shadow-sm mb-6">
              <MessageSquare className="h-12 w-12" style={{ color: T.g200 || T.g100 }} />
            </div>
            <p className="font-bold text-lg" style={{ color: T.ink }}>{t('messages.noConversations')}</p>
            <p className="text-sm mt-2 max-w-[240px]" style={{ color: T.muted }}>
              {t('messages.startWithButton')}
            </p>
            <Button 
              onClick={openNewConversationDialog}
              className="mt-8 rounded-xl px-8 font-bold shadow-md"
              style={{ backgroundColor: T.g600, color: T.white }}
            >
              {t('messages.newConversation')}
            </Button>
          </div>
        )}
      </div>

      {/* Modal Nova Conversa (Modal Mail) */}
      <Dialog open={newConversationOpen} onOpenChange={setNewConversationOpen}>
        <DialogContent 
          className="sm:max-w-md border-none p-0 overflow-hidden rounded-3xl shadow-2xl"
          style={{ backgroundColor: T.canvas }}
        >
          <div className="p-8">
            <DialogHeader className="mb-6">
              <DialogTitle className="text-2xl font-black tracking-tight" style={{ color: T.ink }}>
                {t('messages.newConversation')}
              </DialogTitle>
              <p className="text-sm font-medium" style={{ color: T.muted }}>
                Selecione um contacto para iniciar a conversa
              </p>
            </DialogHeader>
            
            <div className="relative mb-6">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4" style={{ color: T.faint }} />
              <Input
                placeholder={t('messages.searchUser')}
                value={newConvSearchTerm}
                onChange={(e) => setNewConvSearchTerm(e.target.value)}
                className="pl-11 h-12 bg-white border-none rounded-2xl shadow-sm focus-visible:ring-2"
                style={{ '--tw-ring-color': T.gBorder } as React.CSSProperties}
              />
            </div>

            <div className="max-h-[350px] overflow-y-auto pr-2 space-y-2 custom-scrollbar">
              {filteredUsers.length === 0 ? (
                <div className="py-12 text-center">
                  <p className="text-sm font-medium" style={{ color: T.muted }}>
                    {newConvSearchTerm ? t('messages.noUserFound') : 'Nenhum contacto disponível'}
                  </p>
                </div>
              ) : (
                filteredUsers.map((usr) => (
                  <div
                    key={usr.id}
                    onClick={() => {
                      startConversation(usr.id, usr.full_name, usr.avatar_url);
                      setNewConversationOpen(false);
                    }}
                    className="flex items-center gap-4 p-3 rounded-2xl cursor-pointer transition-all hover:bg-white hover:shadow-sm group"
                  >
                    <Avatar className="h-12 w-12 border-2 border-transparent group-hover:border-g100 transition-all">
                      <AvatarImage src={usr.avatar_url || "/default-avatar.png"} />
                      <AvatarFallback style={{ backgroundColor: T.g100, color: T.g700 }}>
                        {usr.full_name.charAt(0).toUpperCase()}
                      </AvatarFallback>
                    </Avatar>
                    <div className="flex-1">
                      <p className="font-bold text-sm" style={{ color: T.ink }}>{usr.full_name}</p>
                      <p className="text-[10px] font-bold uppercase tracking-wider" style={{ color: T.g600 }}>
                        Disponível
                      </p>
                    </div>
                    <div 
                      className="h-8 w-8 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                      style={{ backgroundColor: T.g50 }}
                    >
                      <Plus className="h-4 w-4" style={{ color: T.g600 }} />
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
          
          <div className="px-8 py-4 border-t flex justify-end" style={{ borderColor: T.rule, backgroundColor: T.white }}>
            <Button 
              variant="ghost" 
              onClick={() => setNewConversationOpen(false)}
              className="rounded-xl font-bold"
              style={{ color: T.muted }}
            >
              Cancelar
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      <style dangerouslySetInnerHTML={{ __html: `
        .custom-scrollbar::-webkit-scrollbar {
          width: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: ${T.rule};
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: ${T.faint};
        }
      `}} />
    </div>
  );
};

export default ConversationsList;

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { CalendarIcon, ArrowLeft, Package, Upload, LogOut } from "lucide-react";
import { format, addDays } from "date-fns";
import { ptBR } from "date-fns/locale";
import { cn } from "@/lib/utils";
import { useNavigate } from "react-router-dom";
import { useToast } from "@/hooks/use-toast";
import { angolaProvinces } from "@/data/angola-locations";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";

const FarmerFormWithAuth = () => {
  const navigate = useNavigate();
  const { toast } = useToast();
  const { user, userProfile, logout } = useAuth();
  const [date, setDate] = useState<Date>();
  const [photos, setPhotos] = useState<FileList | null>(null);
  const [selectedProvince, setSelectedProvince] = useState<string>("");
  const [selectedMunicipality, setSelectedMunicipality] = useState<string>("");
  const [productType, setProductType] = useState<string>("");
  const [quantity, setQuantity] = useState<string>("");
  const [price, setPrice] = useState<string>("");
  const [logisticsAccess, setLogisticsAccess] = useState<string>("");
  const [farmerName, setFarmerName] = useState<string>("");
  const [contact, setContact] = useState<string>("");
  const [loading, setLoading] = useState(false);
  
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (date && date < addDays(new Date(), 30)) {
      toast({
        title: "Erro de validação",
        description: "Só pode publicar produtos com previsão mínima de 30 dias antes da colheita",
        variant: "destructive",
      });
      return;
    }

    if (!user) {
      toast({
        title: "Erro de autenticação",
        description: "Você precisa estar logado para publicar um produto",
        variant: "destructive",
      });
      return;
    }

    setLoading(true);
    try {
      // Upload photos to Supabase Storage if any
      const photoUrls: string[] = [];
      if (photos && photos.length > 0) {
        for (let i = 0; i < Math.min(photos.length, 3); i++) {
          const file = photos[i];
          const fileExt = file.name.split('.').pop();
          const fileName = `${user.id}-${Date.now()}-${i}.${fileExt}`;
          
          const { error: uploadError } = await supabase.storage
            .from('product-photos')
            .upload(fileName, file);

          if (uploadError) throw uploadError;
          
          const { data: urlData } = supabase.storage
            .from('product-photos')
            .getPublicUrl(fileName);
          
          if (urlData) {
            photoUrls.push(urlData.publicUrl);
          }
        }
      }

      // Insert product into database
      const { error } = await supabase
        .from('products')
        .insert({
          user_id: user.id,
          product_type: productType,
          quantity: parseInt(quantity),
          harvest_date: date?.toISOString(),
          price: parseFloat(price),
          province_id: selectedProvince,
          municipality_id: selectedMunicipality,
          logistics_access: logisticsAccess as 'sim' | 'nao' | 'parcial',
          farmer_name: farmerName,
          contact: contact,
          photos: photoUrls.length > 0 ? photoUrls : null,
          status: 'active'
        });

      if (error) throw error;

      toast({
        title: "Produto publicado com sucesso!",
        description: "Seu produto foi registrado e será analisado pela equipa AgriLink.",
      });
      
      // Reset form
      setDate(undefined);
      setPhotos(null);
      setSelectedProvince("");
      setSelectedMunicipality("");
      setProductType("");
      setQuantity("");
      setPrice("");
      setLogisticsAccess("");
      setFarmerName("");
      setContact("");
      
    } catch (error: any) {
      toast({
        title: "Erro ao publicar produto",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await logout();
    navigate('/login');
  };

  const minDate = addDays(new Date(), 30);

  const availableMunicipalities = selectedProvince 
    ? angolaProvinces.find(p => p.id === selectedProvince)?.municipalities || []
    : [];

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <div className="bg-gradient-primary text-primary-foreground p-4">
        <div className="container mx-auto flex justify-between items-center">
          <div className="flex items-center gap-4">
            <Button 
              variant="ghost" 
              size="sm" 
              onClick={() => navigate('/dashboard')}
              className="text-primary-foreground hover:bg-primary-foreground/10"
            >
              <ArrowLeft className="mr-2 h-4 w-4" />
              Dashboard
            </Button>
            <div>
              <h1 className="text-2xl font-bold">Publicar Produto</h1>
              <p className="text-primary-foreground/80">
                Bem-vindo, {userProfile?.full_name || user?.email}
              </p>
            </div>
          </div>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleLogout}
            className="text-primary-foreground hover:bg-primary-foreground/10"
          >
            <LogOut className="mr-2 h-4 w-4" />
            Sair
          </Button>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        <div className="max-w-2xl mx-auto">
          <Card className="shadow-medium border-card-border">
            <CardHeader className="bg-gradient-card">
              <CardTitle className="flex items-center gap-3">
                <Package className="h-6 w-6 text-primary" />
                Dados do Produto
              </CardTitle>
              <CardDescription>
                Preencha todos os campos para publicar seu produto agrícola
              </CardDescription>
            </CardHeader>
            
            <CardContent className="p-6">
              <form onSubmit={handleSubmit} className="space-y-6">
                <div className="space-y-2">
                  <Label htmlFor="produto">Produto 🌱</Label>
                  <Select value={productType} onValueChange={setProductType} required>
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione o produto" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="milho">Milho</SelectItem>
                      <SelectItem value="feijao">Feijão</SelectItem>
                      <SelectItem value="batata">Batata</SelectItem>
                      <SelectItem value="mandioca">Mandioca</SelectItem>
                      <SelectItem value="arroz">Arroz</SelectItem>
                      <SelectItem value="soja">Soja</SelectItem>
                      <SelectItem value="cafe">Café</SelectItem>
                      <SelectItem value="banana">Banana</SelectItem>
                      <SelectItem value="tomate">Tomate</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="fotos">Fotografias do produto 📸</Label>
                  <div className="relative">
                    <Upload className="absolute left-3 top-3 h-4 w-4 text-muted-foreground z-10" />
                    <Input
                      id="fotos"
                      type="file"
                      accept="image/*"
                      multiple
                      onChange={(e) => setPhotos(e.target.files)}
                      className="cursor-pointer pl-10"
                    />
                  </div>
                  <p className="text-xs text-muted-foreground">
                    Adicione até 3 fotos do seu produto (opcional)
                  </p>
                  {photos && photos.length > 0 && (
                    <div className="text-sm text-success">
                      ✓ {photos.length} foto(s) selecionada(s)
                    </div>
                  )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="quantidade">Quantidade prevista (kg)</Label>
                    <Input
                      id="quantidade"
                      type="number"
                      min="1000"
                      step="100"
                      value={quantity}
                      onChange={(e) => setQuantity(e.target.value)}
                      placeholder="Ex: 50000"
                      required
                    />
                    <p className="text-xs text-muted-foreground">
                      Mínimo 1.000 kg
                    </p>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="preco">Preço provável (Kz/kg)</Label>
                    <Input
                      id="preco"
                      type="number"
                      min="1"
                      step="0.01"
                      value={price}
                      onChange={(e) => setPrice(e.target.value)}
                      placeholder="Ex: 210.50"
                      required
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <Label>Data estimada da colheita 📅</Label>
                  <Popover>
                    <PopoverTrigger asChild>
                      <Button
                        variant="outline"
                        className={cn(
                          "w-full justify-start text-left font-normal",
                          !date && "text-muted-foreground"
                        )}
                      >
                        <CalendarIcon className="mr-2 h-4 w-4" />
                        {date ? format(date, "PPP", { locale: ptBR }) : "Selecione a data"}
                      </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-auto p-0" align="start">
                      <Calendar
                        mode="single"
                        selected={date}
                        onSelect={setDate}
                        disabled={(date) => date < minDate}
                        initialFocus
                        className="p-3"
                      />
                    </PopoverContent>
                  </Popover>
                  <p className="text-xs text-muted-foreground">
                    Mínimo de 30 dias a partir de hoje
                  </p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Província 🗺️</Label>
                    <Select value={selectedProvince} onValueChange={(value) => {
                      setSelectedProvince(value);
                      setSelectedMunicipality("");
                    }} required>
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione a província" />
                      </SelectTrigger>
                      <SelectContent>
                        {angolaProvinces.map((province) => (
                          <SelectItem key={province.id} value={province.id}>
                            {province.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label>Município 📍</Label>
                    <Select 
                      value={selectedMunicipality} 
                      onValueChange={setSelectedMunicipality} 
                      required
                      disabled={!selectedProvince}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder={selectedProvince ? "Selecione o município" : "Primeiro selecione a província"} />
                      </SelectTrigger>
                      <SelectContent>
                        {availableMunicipalities.map((municipality) => (
                          <SelectItem key={municipality.id} value={municipality.id}>
                            {municipality.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="space-y-2">
                  <Label>Acesso logístico 🚛</Label>
                  <Select value={logisticsAccess} onValueChange={setLogisticsAccess} required>
                    <SelectTrigger>
                      <SelectValue placeholder="Nível de acesso" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="sim">Fácil - Estrada alcatroada</SelectItem>
                      <SelectItem value="parcial">Médio - Terra batida em bom estado</SelectItem>
                      <SelectItem value="nao">Difícil - Acesso limitado</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="agricultor">Nome do Agricultor/Cooperativa</Label>
                    <Input
                      id="agricultor"
                      value={farmerName}
                      onChange={(e) => setFarmerName(e.target.value)}
                      placeholder="Ex: Cooperativa Boa Colheita"
                      required
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="contato">Contato 📞</Label>
                    <Input
                      id="contato"
                      type="tel"
                      value={contact}
                      onChange={(e) => setContact(e.target.value)}
                      placeholder="Ex: +244 xxx xxx xxx"
                      required
                    />
                  </div>
                </div>

                <Button 
                  type="submit" 
                  className="w-full bg-primary hover:bg-primary-hover" 
                  size="lg"
                  disabled={loading}
                >
                  {loading ? 'Publicando...' : 'Publicar Produto'}
                </Button>
              </form>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
};

